import{_ as t,c as a,a1 as s,o as i}from"./chunks/framework.BDxlaA_J.js";const h=JSON.parse('{"title":"Hiding Files using NTFS streams","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/8-NTFS-Streams.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/8-NTFS-Streams.md"}'),r={name:"categories/ethical-hacking-labs/5-system-hacking/8-NTFS-Streams.md"};function n(o,e,c,d,l,g){return i(),a("div",null,e[0]||(e[0]=[s('<h1 id="hiding-files-using-ntfs-streams" tabindex="-1">Hiding Files using NTFS streams <a class="header-anchor" href="#hiding-files-using-ntfs-streams" aria-label="Permalink to &quot;Hiding Files using NTFS streams&quot;">​</a></h1><p>A stream consists of data associated with a main file directory (known as the main unnamed stream). Each file and directory in NTFS can have multiple data streams that are generally hidden from the user.</p><p><a href="https://docs.microsoft.com/en-us/sysinternals/downloads/streams" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/sysinternals/downloads/streams</a></p><p>NTFS supersedes the FAT file system as the preferred file system for Microsoft Windows operating systems. NTFS has several improvements over FAT and HPFS (High Performance File System), such as improved support for metadata and the use of advanced data structures.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>How to hide files usign NTFS streams.</li></ul><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Windows 7, 8, 10 or Windows Server 2012, 2016.</li></ul><h2 id="hiding-data-using-ntfs-streams" tabindex="-1">Hiding Data using NTFS streams <a class="header-anchor" href="#hiding-data-using-ntfs-streams" aria-label="Permalink to &quot;Hiding Data using NTFS streams&quot;">​</a></h2><p>Make sure the <strong>C:\\drive</strong> file system is <strong>NTFS</strong> format. To check this, go to <strong>Computer</strong> and right click C:\\ and click Properties.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/47c51699608fdb618bf4f38b8721c9cdb0ce7288/NTFS-1.png" alt="NFTS-Info-1"></p><ol><li><p>Open Windows Explorer and create a <strong>new folder</strong> called <strong>trick</strong> inside the <strong>C:</strong> drive.</p></li><li><p>Go to <strong>C:\\windows\\system32</strong> and copy the <strong>calc.exe</strong> to the <strong>trick</strong> folder. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b1b0f3cef708249202b1679f71d1acd2588ac6fa/NTFS-calc-copy2.png" alt="Calc-copy"></p></li><li><p>Launch the <strong>command prompt</strong> as Administrator, and navigate to <strong>C:\\trick</strong>. <code>cd C:\\trick</code></p></li><li><p>Create a readme.txt file, type Hello World inside of it and save the file. <code>notepad readme.txt</code></p></li><li><p>Back to command prompt and type <strong>dir</strong> to list the files on the current folder. <strong>Note the file size of readme.txt.</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bba37bcabedc43533fb1c84a35ede0745af44638/ntfs-6.png" alt="Readme-Size"></p></li><li><p>Now hide <strong>calc.exe</strong> inside the <strong>readme.txt</strong> by typing: <code>type c:\\trick\\calc.exe &gt; c:\\trick\\readme.txt:calc.exe</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bba37bcabedc43533fb1c84a35ede0745af44638/ntfs-7.png" alt="ntfs-4"></p></li><li><p>Type <strong>dir</strong> again and note the file size of <strong>readme.txt</strong> did not change.</p></li><li><p>Back to the <strong>c:\\trick</strong> and <strong>delete the calc.exe</strong>.</p></li></ol><h2 id="execute-the-hidden-application" tabindex="-1">Execute the Hidden Application <a class="header-anchor" href="#execute-the-hidden-application" aria-label="Permalink to &quot;Execute the Hidden Application&quot;">​</a></h2><ol start="9"><li><p>Create a symlink: <code>mklink backdoor.exe readme.txt:calc.exe</code></p></li><li><p>Execute the backdoor.exe by typing: <code>backdoor.exe</code><br><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e97b7c0d62642eaa8e502a1b51268913c67de3c3/NTFS-calc-5.png" alt="ntfs-5"></p></li></ol><p>Attackers may hide malicious files from being visible to the legitimate users by using NTFS streams and execute them whenever required.</p>',15)]))}const p=t(r,[["render",n]]);export{h as __pageData,p as default};
